#include <bits/stdc++.h>
using namespace std;
struct BangYou{
	string name,job;
	long long val,level;
	int id;
}a[120];
map<string,int> dj;

/*bool cmp1(BangYou x,BangYou y){
	return x.val>=y.val;
}
bool cmp2(BangYou x,BangYou y){
	if(dj[x.job]==dj[y.job])
		return x.level>=y.level;
	return dj[x.job]>=dj[y.job];
}*/

int n;
int main(){
	//ios::sync_with_stdio(false);
	//cin.tie(0),cout.tie(0);
	dj["BangZhu"]=6,dj["FuBangZhu"]=5,dj["HuFa"]=4,dj["ZhangLao"]=3,dj["TangZhu"]=2,dj["JingYing"]=1,dj["BangZhong"]=0;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i].name>>a[i].job>>a[i].val>>a[i].level;
		a[i].id=i;
	}
	for(int i=n;i;i--)
		for(int j=1;j<i;j++)
			if(a[j].val<a[j+1].val)
				swap(a[j],a[j+1]);
	int sum=0;
	for(int i=1;i<=n;i++){
		if(a[i].job=="BangZhu" || a[i].job=="FuBangZhu")
			continue;
		sum++;
		if(sum<=2)
			a[i].job="HuFa";
		else if(sum<=6)
			a[i].job="ZhangLao";
		else if(sum<=13)
			a[i].job="TangZhu";
		else if(sum<=38)
			a[i].job="JingYing";
		else
			a[i].job="BangZhong";
	}
	for(int i=n;i;i--)
		for(int j=1;j<i;j++){
			if(dj[a[j].job]<dj[a[j+1].job])
				swap(a[j],a[j+1]);
			else if(dj[a[j].job]==dj[a[j+1].job] && a[j].level<a[j+1].level)
				swap(a[j],a[j+1]);
			else if(dj[a[j].job]==dj[a[j+1].job] && a[j].level==a[j+1].level && a[j].id>a[j+1].id)
				swap(a[j],a[j+1]);
		}
	for(int i=1;i<=n;i++){
		cout<<a[i].name<<' '<<a[i].job<<' ';
		printf("%lld\n",a[i].level);
	}
	return 0;
}
